 1→import { useCallback } from 'react';
 2→import { useShallow } from 'zustand/shallow';
 3→import { useRootStore } from '~/store';
 4→import {
 5→  ParameterPointsProgramStatus,
 6→  PointsBalanceStatus,
 7→  PointsProductsStatus,
 8→} from '../models';
 9→import {
10→  getParameterPointsProgram,
11→  getPointsBalance,
12→  getPointsProducts,
13→} from '../services';
14→
15→export function usePoints() {
16→  const pointsProducts = useRootStore(
17→    useShallow(state => state.pointsProducts),
18→  );
19→  const pointsBalance = useRootStore(useShallow(state => state.pointsBalance));
20→  const parameterPointsProgram = useRootStore(
21→    useShallow(state => state.parameterPointsProgram),
22→  );
23→
24→  const requestInitialData = useCallback(async () => {
25→    await Promise.all([
26→      getPointsBalance(),
27→      getPointsProducts(),
28→      getParameterPointsProgram(),
29→    ]);
30→  }, []);
31→
32→  const requestPointsBalance = useCallback(async () => {
33→    await getPointsBalance();
34→  }, []);
35→
36→  const requestPointsProducts = useCallback(async () => {
37→    await getPointsProducts();
38→  }, []);
39→
40→  const requestParameterization = useCallback(async () => {
41→    await getParameterPointsProgram();
42→  }, []);
43→
44→  const clear = useCallback(() => {
45→    const { pointsProductsActions } = useRootStore.getState();
46→    pointsProductsActions.reset();
47→  }, []);
48→
49→  const clearBalance = useCallback(() => {
50→    const { pointsExtractActions } = useRootStore.getState();
51→    pointsExtractActions.clearBalance();
52→  }, []);
53→
54→  return {
55→    points: pointsBalance.points,
56→    isLoadingBalance: pointsBalance.status === PointsBalanceStatus.LOADING,
57→    isErrorBalance: pointsBalance.status === PointsBalanceStatus.ERROR,
58→    products: pointsProducts.products,
59→    isLoadingProducts: pointsProducts.status === PointsProductsStatus.LOADING,
60→    isErrorProducts: pointsProducts.status === PointsProductsStatus.ERROR,
61→    pointsQuantity: parameterPointsProgram.pointsQuantity,
62→    conversionFactor: parameterPointsProgram.conversionFactor,
63→    isLoadingParameterization:
64→      parameterPointsProgram.status === ParameterPointsProgramStatus.LOADING,
65→    isErrorParameterization:
66→      parameterPointsProgram.status === ParameterPointsProgramStatus.ERROR,
67→    requestPointsBalance,
68→    requestPointsProducts,
69→    requestParameterization,
70→    requestInitialData,
71→    clear,
72→    clearBalance,
73→  };
74→}
