27→  PointsProductsSlice,
28→  createPointsProductsSlice,
29→} from './products.store';
30→import { RescueSlice, createRescueSlice } from './rescue.store';
31→
32→export type RewardsProgramRootStore = ParameterPointsProgramSlice &
33→  PermissionSlice &
34→  AirlineMilesSlice &
35→  PointsExtractSlice &
36→  PointsProductsSlice &
37→  RescueSlice &
38→  MarketplaceSlice &
39→  OrderDetailSlice;
40→
41→type Slice<T> = StateCreator<RewardsProgramRootStore, [], [], T>;
42→const asSlice = <T>(slice: StateCreator<RewardsProgramRootStore, [], [], T>) =>
43→  slice as Slice<T>;
44→
45→export function setRewardsProgramSlices<T extends RewardsProgramRootStore>(
46→  ...a: Parameters<Slice<T>>
47→) {
48→  return {
49→    ...asSlice<ParameterPointsProgramSlice>(createParameterPointsProgramSlice)(
50→      ...a,
51→    ),
52→    ...asSlice<PermissionSlice>(createPermissionSlice)(...a),
53→    ...asSlice<AirlineMilesSlice>(createAirlineMilesSlice)(...a),
54→    ...asSlice<PointsExtractSlice>(createPointsExtractSlice)(...a),
55→    ...asSlice<PointsProductsSlice>(createPointsProductsSlice)(...a),
56→    ...asSlice<RescueSlice>(createRescueSlice)(...a),
57→    ...asSlice<MarketplaceSlice>(createMarketplaceSlice)(...a),
58→    ...asSlice<OrderDetailSlice>(createOrderDetailSlice)(...a),
59→  };
60→}
